462→            <EmptyState
463→              icon={<SearchEmptyIcon />}
464→              title="No Results"
465→              description="Try a different search term or filter"
466→            />
467→          ) : (
468→            <List
469→              itemCount={totalItemCount}
470→              onActiveIndexChange={handleActiveIndexChange}
471→              onAction={handleAction}
472→            >
473→              {(() => {
474→                let globalIndex = 0;
475→                const sections: ReactNode[] = [];
476→
477→                if (folders.length > 0) {
478→                  sections.push(
479→                    <ListSection key="folders" title="Folders">
480→                      {folders.map(entry =>
481→                        renderFileItem(entry, globalIndex++))}
482→                    </ListSection>,
483→                  );
484→                }
485→
486→                if (files.length > 0) {
487→                  sections.push(
488→                    <ListSection key="files" title="Files">
489→                      {files.map(entry => renderFileItem(entry, globalIndex++))}
490→                    </ListSection>,
491→                  );
492→                }
493→
494→                return sections;
495→              })()}
496→            </List>
497→          )}
498→        </div>
499→      </div>
500→      <ActionPanel
501→        contextLabel="File Search"
502→        actions={[
503→          {
504→            label: 'Open',
505→            shortcut: <Kbd keys={['↵']} />,
506→          },
507→          {
508→            label: 'Actions',
509→            shortcut: (
510→              <Kbd
511→                keys={[
512→                  '⌘',
513→                  'K',
514→                ]}
515→              />
516→            ),
517→            onClick: toggleActions,
518→          },
519→        ]}
520→        dropdownOpen={actionsOpen}
521→        dropdownSections={dropdownSections}
522→        onDropdownClose={closeActions}
523→      />
524→      {alertState && (
525→        <Alert
526→          title={alertState.title}
527→          message={alertState.message}
528→          icon={alertState.icon}
529→          primaryAction={alertState.primaryAction}
530→          dismissAction={alertState.dismissAction}
531→          onDismiss={dismissAlert}
532→        />
533→      )}
534→      <HUDContainer items={hudItems} />
535→    </>
536→  );
537→}
