import { useMemo } from 'react';
import { fuzzyScore } from '../../utils/fuzzy_search';
import './highlighted_text.scss';

interface HighlightedTextProps {
  text: string;
  query: string;
  className?: string;
}

export function HighlightedText({
  text,
  query,
  className,
}: HighlightedTextProps) {
  const segments = useMemo(() => {
    if (!query) return null;
    const result = fuzzyScore(query, text);
    if (!result || result.indices.length === 0) return null;

    const indexSet = new Set(result.indices);
    const parts: {
      text: string;
      highlighted: boolean;
    }[] = [];
    let current = '';
    let currentHighlighted = false;

    for (let i = 0; i < text.length; i++) {
      const isHighlighted = indexSet.has(i);
      if (i === 0) {
        currentHighlighted = isHighlighted;
        current = text[i]!;
      } else if (isHighlighted === currentHighlighted) {
        current += text[i]!;
      } else {
        parts.push({
          text: current,
          highlighted: currentHighlighted,
        });
        current = text[i]!;
        currentHighlighted = isHighlighted;
      }
    }
    if (current) {
      parts.push({
        text: current,
        highlighted: currentHighlighted,
      });
    }

    return parts;
  }, [
    text,
    query,
  ]);

  if (!segments) {
    return <span className={className}>{text}</span>;
  }

  return (
    <span className={className}>
      {segments.map((segment, i) =>
        segment.highlighted ? (
          <mark key={i} className="highlighted-text__match">
            {segment.text}
          </mark>
        ) : (
          <span key={i}>{segment.text}</span>
        ))}
    </span>
  );
}

